-- V90 governed final node catalog consolidation

DELETE FROM node_type_registry WHERE type_key NOT IN ('START','END','DIRECT_RETURN','DIRECT_CALL','EVENT_TRIGGER','MQ_TRIGGER','SCHEDULED_TRIGGER','IF_CONDITION','SPLIT','WAIT','HUB','AGGREGATE','THRESHOLD','API_CALL','SEND_MQ','GROOVY','SEND_MESSAGE','TAGGER','COMMIT_ACTION','SUB_FLOW_REF');

ON DUPLICATE KEY UPDATE
  type_name = VALUES(type_name),
  category = VALUES(category),
  handler_class = VALUES(handler_class),
  config_schema = VALUES(config_schema),
  output_schema = VALUES(output_schema),
  outlet_schema = VALUES(outlet_schema),
  summary_template = VALUES(summary_template),
  runtime_policy_schema = VALUES(runtime_policy_schema),
  risk_level = VALUES(risk_level),
  is_trigger = VALUES(is_trigger),
  is_terminal = VALUES(is_terminal),
  description = VALUES(description),
  enabled = VALUES(enabled);
